{"code": "import os
import re

concepts_dir = "/home/julius/knowledge-base/knowledge-base-agent/wiki/concepts/"
files = sorted([f for f in os.listdir(concepts_dir) if f.endswith('.md')])

# Extract frontmatter status from each file
for fname in files:
    fpath = os.path.join(concepts_dir, fname)
    with open(fpath, 'r') as f:
        content = f.read()

    # Parse YAML frontmatter
    status = "unknown"
    if content.startswith('---'):
        end = content.find('---', 3)
        if end != -1:
            frontmatter = content[3:end].strip()
            # Extract status
            for line in frontmatter.split('\n'):
                if line.strip().startswith('status:'):
                    status = line.split(':', 1)[1].strip()
                    break

    print(f"{fname}: status={status}")"}
